// // This D Flip-Flop captures the input data on the falling edge of the clock signal and outputs it on the q signal. If the reset signal is deasserted, the output q will not be reset to 0.
module d_flip_flop(
  input clk,
  input rst,
  input d,
  output reg q
);

  always @(posedge clk) begin
    if (rst) begin
      q <= 1'b0;
    end
    else begin
      q <= d;
    end
  end

endmodule
